sql:
SELECT function_name
FROM molecular_functions
WHERE go_term = 'G-protein coupled photoreceptor activity';

SELECT function_id
FROM protein_functions
WHERE confidence_score = (SELECT MAX(confidence_score) FROM protein_functions);

SELECT category_name
FROM function_categories
WHERE category_id = 0;

SELECT COUNT(*) AS total_functions
FROM molecular_functions
WHERE biological_significance IS NOT NULL AND biological_significance != '';

SELECT COUNT(function_id) AS receptor_activity_count
FROM function_category_relationships
WHERE category_id = (SELECT category_id FROM function_categories WHERE category_name = 'Receptor Activity');

SELECT DISTINCT user_id
FROM access_logs
WHERE access_date >= date('now', '-30 days');

SELECT COUNT(category_id) AS category_count, category_name
     FROM function_categories
     GROUP BY category_name;

SELECT go_name 
FROM gene_ontology 
WHERE go_term = (SELECT go_term FROM molecular_functions WHERE function_id = 0);

SELECT COUNT(*) 
FROM function_categories 
WHERE category_name = 'Enzyme Activity';

SELECT biological_significance, COUNT(function_id) AS function_count
FROM molecular_functions
GROUP BY biological_significance;

external_knowledge:
Access count refers to the number of times a molecular function's data was accessed; Average access date is the average date of access over time for a molecular function; 
A molecular function can be associated with multiple categories in a hierarchical structure; 
The confidence score in protein interactions represents the reliability of the evidence supporting a protein's association with a function.

sql:
SELECT COUNT(function_id) AS function_count
FROM project_functions
WHERE project_id = 0;

SELECT category_id, COUNT(function_id) AS function_count
FROM function_category_relationships
GROUP BY category_id;

SELECT description
FROM molecular_functions
WHERE go_term IN (
  SELECT go_term
  FROM gene_ontology
  WHERE go_name IN (
    'G-protein coupled photoreceptor activity',
    'G-protein coupled receptor activity'
  )
);

SELECT project_id, function_id
FROM project_functions
WHERE priority = 'high';

SELECT COUNT(function_id) AS primary_function_count
FROM function_category_relationships
WHERE relationship_type = 'primary';
